/**
 * WorkService - Handles saving and retrieving student artworks.
 * Uses localStorage for persistence in this prototype.
 */
const WorkService = {
    STORAGE_KEY: 'artthink_my_works',

    /**
     * Saves the current canvas state as a new work with a custom title.
     */
    saveWork(canvas, title) {
        const works = this.getWorks();
        const dataUrl = canvas.toDataURL('image/png');

        const newWork = {
            id: Date.now(),
            title: title || this.generateRandomTitle(),
            date: new Date().toLocaleDateString('zh-CN', { month: 'long', day: 'numeric' }),
            image: dataUrl,
            student: "三年级 晓明" // Mock student data
        };

        works.unshift(newWork); // Add to beginning
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(works));
        return newWork;
    },

    /**
     * Shows a modal to name the artwork before saving.
     */
    saveWithNaming(canvas) {
        const modal = document.createElement('div');
        modal.className = 'custom-modal-overlay';
        modal.innerHTML = `
            <div class="custom-modal">
                <p>为你的画作起个好听的名字吧！</p>
                <input type="text" id="artwork-name-input" class="modal-input" placeholder="输入画作名称..." maxlength="15">
                <div class="modal-btns">
                    <button class="modal-btn cancel">不保存了</button>
                    <button class="modal-btn confirm" style="background:var(--accent-color, #0084D0); color:white;">确认保存</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

        const input = modal.querySelector('#artwork-name-input');
        input.focus();

        modal.querySelector('.cancel').onclick = () => modal.remove();
        modal.querySelector('.confirm').onclick = () => {
            const title = input.value.trim() || '未命名的杰作';
            this.saveWork(canvas, title);
            modal.remove();
            this.showToast(`✨ “${title}” 已存入我的作品！`);
        };

        // Support Enter key
        input.onkeydown = (e) => {
            if (e.key === 'Enter') modal.querySelector('.confirm').click();
        };
    },

    /**
     * Deletes a work by ID.
     */
    deleteWork(id) {
        this.showConfirmModal('确定要删除这幅杰作吗？', () => {
            const works = this.getWorks().filter(w => w.id !== id);
            localStorage.setItem(this.STORAGE_KEY, JSON.stringify(works));
            this.renderWorks('my-works-grid');
            this.showToast('作品已删除');
        }, true);
    },

    showConfirmModal(message, onConfirm, isDelete = false) {
        // Simple custom modal
        const modal = document.createElement('div');
        modal.className = 'custom-modal-overlay';
        modal.innerHTML = `
            <div class="custom-modal">
                <p>${message}</p>
                <div class="modal-btns">
                    <button class="modal-btn cancel">取消</button>
                    <button class="modal-btn ${isDelete ? 'confirm-delete' : 'confirm'}">确定</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

        modal.querySelector('.cancel').onclick = () => modal.remove();
        
        const confirmBtn = modal.querySelector(isDelete ? '.confirm-delete' : '.confirm');
        confirmBtn.onclick = () => {
            onConfirm();
            modal.remove();
        };
    },

    showChoiceModal(message, btn1Label, on1, btn2Label, on2) {
        const modal = document.createElement('div');
        modal.className = 'custom-modal-overlay';
        modal.innerHTML = `
            <div class="custom-modal" style="max-width: 320px;">
                <p style="font-weight: 800; font-size: 16px; margin-bottom: 20px;">${message}</p>
                <div class="choice-btns" style="display: flex; gap: 10px; flex-direction: column;">
                    <button class="modal-btn opt1" style="background: #FFF; color: #333; border: 2px solid #E2E3E0; padding: 12px; display: flex; align-items: center; justify-content: center; gap: 10px;">
                        <svg viewBox="0 0 24 24" width="20" height="20" fill="#0084D0"><path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V5h14v14zm-7-2h2v-2h2v-2h-2v-2h-2v2H8v2h2v2z"/></svg>
                        <span>${btn1Label}</span>
                    </button>
                    <button class="modal-btn opt2" style="background: #FFF; color: #333; border: 2px solid #E2E3E0; padding: 12px; display: flex; align-items: center; justify-content: center; gap: 10px;">
                        <svg viewBox="0 0 24 24" width="20" height="20" fill="#FF4081"><path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2zM8.5 13.5l2.5 3.01L14.5 12l4.5 6H5l3.5-4.5z"/></svg>
                        <span>${btn2Label}</span>
                    </button>
                    <button class="modal-btn cancel" style="margin-top: 10px; color: #999; font-size: 12px; border: none; background: none;">先不用了</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

        modal.querySelector('.opt1').onclick = () => { on1(); modal.remove(); };
        modal.querySelector('.opt2').onclick = () => { on2(); modal.remove(); };
        modal.querySelector('.cancel').onclick = () => modal.remove();
    },

    showToast(message) {
        const toast = document.createElement('div');
        toast.className = 'custom-toast';
        toast.innerText = message;
        document.body.appendChild(toast);

        // Trigger animation
        setTimeout(() => toast.classList.add('show'), 100);

        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 400);
        }, 2500);
    },

    /**
     * Sends a work to the gallery (evaluation wall)
     */
    sendToGallery(id) {
        const works = this.getWorks();
        const work = works.find(w => w.id === id);
        if (work) {
            work.isSent = true;
            localStorage.setItem(this.STORAGE_KEY, JSON.stringify(works));
            this.showToast('作品已发送到互评墙！');
            this.renderWorks('my-works-grid');
            
            // Sync to gallery storage
            let galleryWorks = localStorage.getItem('artthink_gallery');
            galleryWorks = galleryWorks ? JSON.parse(galleryWorks) : [];
            // check if already exists
            if (!galleryWorks.find(w => w.id === id)) {
                galleryWorks.unshift(work);
                localStorage.setItem('artthink_gallery', JSON.stringify(galleryWorks));
            }
        }
    },

    /**
     * Shows a full-screen modal to enlarge an image.
     */
    showImageModal(src) {
        const overlay = document.createElement('div');
        overlay.className = 'image-modal-overlay';
        overlay.innerHTML = `
            <div class="image-modal-close">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round">
                    <line x1="18" y1="6" x2="6" y2="18"></line>
                    <line x1="6" y1="6" x2="18" y2="18"></line>
                </svg>
            </div>
            <img src="${src}" class="image-modal-content">
        `;
        document.body.appendChild(overlay);

        // Close logic
        const close = () => {
            overlay.style.opacity = '0';
            setTimeout(() => overlay.remove(), 300);
        };

        overlay.onclick = (e) => {
            if (e.target.tagName !== 'IMG') close();
        };
        overlay.querySelector('.image-modal-close').onclick = close;
        
        // Escape key to close
        const keyHandler = (e) => {
            if (e.key === 'Escape') {
                close();
                document.removeEventListener('keydown', keyHandler);
            }
        };
        document.addEventListener('keydown', keyHandler);
    },

    /**
     * Retrieves all saved works.
     */
    getWorks() {
        // Default 3 photos
        const defaults = [
            'data:image/jpeg;base64,',
            'data:image/jpeg;base64,',
            'data:image/jpeg;base64,'
        ];

        const stored = localStorage.getItem(this.STORAGE_KEY);
        return stored ? JSON.parse(stored) : [];
    },

    /**
     * Renders works into the specified container.
     */
    renderWorks(containerId) {
        const container = document.getElementById(containerId);
        if (!container) return;

        const works = this.getWorks();
        if (works.length === 0) {
            container.innerHTML = `
                <div style="text-align:center; padding:50px; color:#888;">
                    <p style="font-size: 20px;">这里空空如也...</p>
                    <p>快去画布中心创作你的第一幅杰作吧！</p>
                </div>
            `;
            return;
        }

        container.innerHTML = works.map(work => `
            <div class="artwork-card">
                <svg class="pin ${this.getRandomColor()}" viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z"/><circle cx="12" cy="9" r="2.5" fill="#fff"/></svg>
                <img src="${work.image}" alt="${work.title}" class="artwork-img" onclick="WorkService.showImageModal(this.src)" style="cursor: zoom-in;">
                <div class="artwork-info">
                    <h3>${work.title}</h3>
                    <div style="font-size:11px; color:#999;">${work.date}</div>
                </div>
                <div class="artwork-actions">
                    <button class="action-btn btn-delete" onclick="WorkService.deleteWork(${work.id})">
                        <div class="action-icon">
                            <svg viewBox="0 0 24 24"><path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/></svg>
                        </div>
                        <span>删除</span>
                    </button>
                    ${work.isSent ? `
                    <button class="action-btn" disabled style="opacity: 0.5; color: #999;">
                        <div class="action-icon" style="background: #e2e3e0; color: #999;">
                            <svg viewBox="0 0 24 24" fill="currentColor"><path d="M9 16.2L4.8 12l-1.4 1.4L9 19 21 7l-1.4-1.4L9 16.2z"/></svg>
                        </div>
                        <span>已发送</span>
                    </button>
                    ` : `
                    <button class="action-btn" onclick="WorkService.sendToGallery(${work.id})" style="color: var(--primary-color);">
                        <div class="action-icon" style="background: var(--primary-light); color: var(--primary-color);">
                            <svg viewBox="0 0 24 24" fill="currentColor"><path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z"/></svg>
                        </div>
                        <span>发送</span>
                    </button>
                    `}
                    <button class="action-btn btn-comment" onclick="WorkService.showToast('老师点评正在拼命赶来...')">
                        <div class="action-icon">
                            <svg viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h14l4 4V4c0-1.1-.9-2-2-2zm-2 12H6v-2h12v2zm0-3H6V9h12v2zm0-3H6V6h12v2z"/></svg>
                        </div>
                        <span>点评</span>
                    </button>
                </div>
            </div>
        `).join('');
    },

    generateRandomTitle() {
        const adjectives = ["灿烂的", "梦幻的", "未来的", "彩虹般的", "奇妙的", "阳光下"];
        const nouns = ["森林", "城堡", "小船", "花园", "大门", "秘密基地"];
        return adjectives[Math.floor(Math.random() * adjectives.length)] +
            nouns[Math.floor(Math.random() * nouns.length)];
    },

    getRandomColor() {
        const colors = ["red", "blue", "yellow", "pink"];
        return colors[Math.floor(Math.random() * colors.length)];
    }
};

const MaterialService = {
    STORAGE_KEY: 'artthink_materials',
    
    getMaterials() {
        const stored = localStorage.getItem(this.STORAGE_KEY);
        if (stored) {
            let materials = JSON.parse(stored);
            localStorage.setItem(this.STORAGE_KEY, JSON.stringify(materials));
            return materials;
        }
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(defaults));
        return defaults;
    },
    
    addMaterial(dataUrl) {
        const materials = this.getMaterials();
        materials.push(dataUrl);
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(materials));
    },
    
    deleteMaterial(index) {
        WorkService.showConfirmModal('确定要从素材库移出该照片吗？', () => {
            const materials = this.getMaterials();
            materials.splice(index, 1);
            localStorage.setItem(this.STORAGE_KEY, JSON.stringify(materials));
            this.renderMaterials('materials-grid');
            WorkService.showToast('素材已删除');
        }, true);
    },
    
    renderMaterials(containerId) {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        const materials = this.getMaterials();
        if (materials.length === 0) {
            container.innerHTML = `<div style="text-align:center; padding:50px; color:#888;">素材库为空</div>`;
            return;
        }

        container.innerHTML = materials.map((imgUrl, index) => `
            <div class="artwork-card" style="box-shadow: 0 4px 15px rgba(0,0,0,0.05); border: 2px solid #E2E3E0;">
                <img src="${imgUrl}" alt="Material ${index}" class="artwork-img" style="aspect-ratio:1/1; border-radius:12px; margin-bottom: 0;">
                <div class="artwork-info" style="padding: 10px;">
                    <div style="font-size:11px; color:#999; text-align:center;">素材 ${index + 1}</div>
                </div>
                <div class="artwork-actions" style="margin-top: 5px;">
                    <button class="action-btn btn-delete" onclick="MaterialService.deleteMaterial(${index})">
                        <div class="action-icon">
                            <svg viewBox="0 0 24 24"><path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/></svg>
                        </div>
                        <span>删除</span>
                    </button>
                </div>
            </div>
        `).join('');
    }
};
